1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - Next Generation", () => {
6	  it("should return empty array for a single live cell (underpopulation)", () => {
7	    expect(nextGeneration([[0, 0]])).toEqual([]);
8	  });
9	  it("should return empty array for two adjacent cells, each with one neighbor (underpopulation)", () => {
10	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
11	  });
12	  it("should keep alive a cell with three live neighbors (survival)", () => {
13	    // ###      .#.
14	    // .#.  ->  .#.
15	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toEqual([
16	      [1, 0],
17	      [1, 1],
18	    ]);
19	  });
20	  it.todo("should kill a live cell with more than three live neighbors (overpopulation)");
21	  it.todo("should bring to life a dead cell with exactly three live neighbors (reproduction)");
22	  it.todo("should keep a block still life unchanged");
23	  it.todo("should rotate a vertical blinker into a horizontal blinker including negative coordinates");
24	});
25

1	export type Cell = [number, number];
2	
3	const isNeighbor = ([x, y]: Cell, [otherX, otherY]: Cell): boolean =>
4	  Math.abs(x - otherX) <= 1 &&
5	  Math.abs(y - otherY) <= 1 &&
6	  !(x === otherX && y === otherY);
7	
8	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
9	  cells.filter((other) => isNeighbor(cell, other)).length;
10	
11	export const nextGeneration = (cells: Cell[]): Cell[] =>
12	  cells.filter((cell) => countLiveNeighbors(cell, cells) >= 3);
